import click
from click.testing import CliRunner

@click.command()
@click.option('--env', type=click.Choice(['dev', 'staging', 'prod']), default='dev')
@click.option('--debug', is_flag=True)
@click.option(
    '--log-level',
    default={
        '--env': {'dev': 'DEBUG', 'staging': 'INFO', 'prod': 'ERROR'},
        '--debug': {'True': 'DEBUG'},
    },
)
def deploy(env, debug, log_level):
    click.echo(f'Deploying to {env} with log level {log_level} (debug={debug})')

runner = CliRunner()
for args in [[], ['--env', 'prod'], ['--env', 'prod', '--debug'], ['--log-level', 'WARN']]:
    r = runner.invoke(deploy, args)
    print(args, '->', repr(r.output), r.exception)
